// Pre-built lookup maps
const byIata = new Map<string, Airport>();
const byIcao = new Map<string, Airport>();
AIRPORTS.forEach(a => { byIata.set(a.iata, a); byIcao.set(a.icao, a); });

export function getAirportByIata(iata: string): Airport | undefined {
  return byIata.get(iata.toUpperCase());
}

export function getAirportByIcao(icao: string): Airport | undefined {
  return byIcao.get(icao.toUpperCase());
}

export function searchAirports(query: string, limit: number = 10): Airport[] {
  const q = query.toUpperCase().trim();
  if (q.length < 2) return [];

  const exactIata = byIata.get(q);
  if (exactIata) return [exactIata];
  const exactIcao = byIcao.get(q);
  if (exactIcao) return [exactIcao];

  return AIRPORTS
    .filter(a =>
      a.iata.startsWith(q) ||
      a.icao.startsWith(q) ||
      a.name.toUpperCase().includes(q) ||
      a.city.toUpperCase().includes(q)
    )
    .slice(0, limit);
}
